// Match BCP-47 tags like en-US, zh-Hans-CN, fr, pt-BR
const bcp47Re = /\b[a-z]{2,3}(?:-[A-Za-z]{4})?(?:-[A-Z]{2}|\d{3})?\b/;
// Match locale numbers (3-5 digits, standalone)
const lcidRe = /\b\d{3,5}\b/;
// Match locale number hex like 0x0409
const hexRe = /\b0x[0-9a-fA-F]{4}\b/;
const hasBcp47 = bcp47Re.test(input);
const hasLcid = lcidRe.test(input);
const hasHex = hexRe.test(input);
return (hasBcp47 || hasLcid || hasHex) ? 0.6 : 0;

