// Build lookup maps
const byLocaleId  = new Map();
const byLcid    = new Map();
const byBcp47   = new Map();
const byDisplay = new Map();
const byLang    = new Map();
const byRegion  = new Map();

for (const row of LOCALES) {
  const [localeId, lcid, bcp47, displayName, language, region] = row;
  if (localeId) byLocaleId.set(localeId, row);
  if (lcid)   byLcid.set(lcid, row);
  if (bcp47)  byBcp47.set(bcp47.toLowerCase(), row);
  if (displayName) byDisplay.set(displayName.toLowerCase(), row);
  if (language)    byLang.set(language.toLowerCase(), row);
  if (region)      byRegion.set(region.toLowerCase(), row);
}

function formatRow(row) {
  const [localeId, lcid, bcp47, displayName, language, region] = row;
  const lcidHex = lcid ? '0x' + lcid.toString(16).toUpperCase().padStart(4, '0') : 'N/A';
  return [
    `Display Name : ${displayName}`,
    `Language     : ${language || 'N/A'}`,
    `Region       : ${region || 'N/A'}`,
    `BCP-47 Tag   : ${bcp47 || 'N/A'}`,
    `Locale ID    : ${localeId || 'N/A'}`,
    `LCID (dec)   : ${lcid || 'N/A'}`,
    `LCID (hex)   : ${lcidHex}`,
  ].join('\n');
}

const results = [];
const seen = new Set();

function addResult(row, matchedToken, matchType) {
  const key = row[0] + '|' + row[2];
  if (seen.has(key)) return;
  seen.add(key);
  results.push(`Matched: "${matchedToken}" (${matchType})\n${formatRow(row)}`);
}

const tokens = input.split(/[,\n;\t]+/).map(s => s.trim()).filter(Boolean);

for (const token of tokens) {
  const num = parseInt(token, 10);
  const hexMatch = token.match(/^0x([0-9a-fA-F]+)$/i);
  const hexNum = hexMatch ? parseInt(hexMatch[1], 16) : NaN;

  // 1. Exact locale number
  if (!isNaN(num) && byLocaleId.has(num)) {
    addResult(byLocaleId.get(num), token, 'Locale Number');
    continue;
  }

  // 2. Hex LCID like 0x0409
  if (!isNaN(hexNum) && byLcid.has(hexNum)) {
    addResult(byLcid.get(hexNum), token, 'LCID (hex)');
    continue;
  }

  // 3. Decimal LCID
  if (!isNaN(num) && byLcid.has(num)) {
    addResult(byLcid.get(num), token, 'LCID (decimal)');
    continue;
  }

  // 4. BCP-47 tag
  const bcp47Key = token.toLowerCase();
  if (byBcp47.has(bcp47Key)) {
    addResult(byBcp47.get(bcp47Key), token, 'BCP-47 Tag');
    continue;
  }

  // 5. Display name
  if (byDisplay.has(bcp47Key)) {
    addResult(byDisplay.get(bcp47Key), token, 'Display Name');
    continue;
  }

  // 6. Language name
  if (byLang.has(bcp47Key)) {
    addResult(byLang.get(bcp47Key), token, 'Language Name');
    continue;
  }

  // 7. Region / country name
  if (byRegion.has(bcp47Key)) {
    addResult(byRegion.get(bcp47Key), token, 'Country/Region');
    continue;
  }

  // 8. Partial / substring match on display name or region
  let found = false;
  for (const [key, row] of byDisplay) {
    if (key.includes(bcp47Key)) {
      addResult(row, token, 'Partial Display Name');
      found = true;
      break;
    }
  }
  if (!found) {
    for (const [key, row] of byRegion) {
      if (key.includes(bcp47Key)) {
        addResult(row, token, 'Partial Country/Region');
        found = true;
        break;
      }
    }
  }
  if (!found) {
    results.push(`Matched: "${token}"\n  (No locale found for this identifier)`);
  }
}

if (results.length === 0) {
  return { output: 'No locale identifiers found.', outputLanguage: 'text' };
}
return { output: results.join('\n\n'), outputLanguage: 'text' };
